import UIKit

class FinancialTradingApp: UIViewController {
    
    // MARK: - Properties
    
    let tradeExecutionManager = TradeExecutionManager()
    let portfolioManager = PortfolioManager()
    
    // MARK: - View Controller Life Cycle
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Set up the trade execution manager
        tradeExecutionManager.delegate = self
        
        // Set up the portfolio manager
        portfolioManager.delegate = self
    }
    
    // MARK: - Trade Execution Methods
    
    func executeTrade(symbol: String, quantity: Int) {
        // Call the trade execution API with the given symbol and quantity
        tradeExecutionManager.executeTrade(symbol: symbol, quantity: quantity)
    }
    
    func cancelTrade(tradeId: String) {
        // Call the trade cancellation API with the given trade ID
        tradeExecutionManager.cancelTrade(tradeId: tradeId)
    }
    
    // MARK: - Portfolio Management Methods
    
    func updatePortfolio() {
        // Call the portfolio update API to retrieve the latest information about the user's portfolio
        portfolioManager.updatePortfolio()
    }
    
    func getPortfolioValue() -> Double {
        // Return the current value of the user's portfolio
        return portfolioManager.portfolioValue
    }
}

// MARK: - TradeExecutionManagerDelegate

extension FinancialTradingApp: TradeExecutionManagerDelegate {
    
    func tradeExecuted(tradeId: String) {
        // Update the user interface to reflect the executed trade
        updatePortfolio()
    }
    
    func tradeCancelled(tradeId: String) {
        // Update the user interface to reflect the cancelled trade
        updatePortfolio()
    }
}

// MARK: - PortfolioManagerDelegate

extension FinancialTradingApp: PortfolioManagerDelegate {
    
    func portfolioUpdated(portfolioValue: Double) {
        // Update the user interface to reflect the updated portfolio value
        updatePortfolio()
    }
}